{
    "level": "B1–B2",
    "intro": "In this topic you will learn <strong>Question Tags</strong> - short questions at the end of a sentence to confirm information or polite communication.",
    "rules": [
        {
            "label": "POSITIVE + NEGATIVE",
            "color": "emerald",
            "text": "<strong>Assertion</strong> + negative tag:",
            "example": "You like coffee, don't you?"
        },
        {
            "label": "NEGATIVE + POSITIVE",
            "color": "blue",
            "text": "<strong>Negation</strong> + positive tag:",
            "example": "You don't like coffee, do You? ↘ / ↗"
        },
        {
            "label": "ІНТОНАЦІЯ",
            "color": "amber",
            "text": "<strong>Падаюча</strong> — підтвердження, <strong>зростаюча</strong> — справжнє питання:",
            "example": "It's nice, isn't it? ↘ / ↗"
        }
    ]
}

{
    "title": "1. What are Question Tags?",
    "intro": "Question tags are short questions at the end of a sentence:",
    "items": [
        {
            "label": "Assertion",
            "title": "She is happy, isn't she?",
            "subtitle": "Positive + negative tag"
        },
        {
            "label": "Negation",
            "title": "She isn't happy, is she?",
            "subtitle": "Negative + positive tag"
        },
        {
            "label": "Basic rule",
            "title": "Statement + opposite tag",
            "subtitle": "Opposite form"
        }
    ]
}

{
    "title": "2. Question Tags with the verb TO BE",
    "sections": [
        {
            "label": "Present Simple — AM/IS/ARE",
            "color": "emerald",
            "description": "With <strong>to be</strong> in the Present Simple, we form a tag with am/is/are:",
            "examples": [
                {
                    "en": "She is happy, isn't she?",
                    "ua": "She is happy, isn't she?"
                },
                {
                    "en": "You are tired, aren't you?",
                    "ua": "You are tired, aren't you?"
                },
                {
                    "en": "He is a doctor, isn't he?[[[CODX_4]]]He is a doctor, isn't he?",
                    "ua": "Він лікар, так?"
                },
                {
                    "en": "They are British, aren't they?",
                    "ua": "They are British, aren't they?"
                }
            ]
        },
        {
            "label": "Negative sentences",
            "color": "sky",
            "description": "If the sentence is negative, the tag becomes positive:",
            "examples": [
                {
                    "en": "She isn't happy, is she?",
                    "ua": "She isn't happy, yes?"
                },
                {
                    "en": "You aren't tired, are you?",
                    "ua": "You aren't tired, are you?"
                },
                {
                    "en": "He isn't a doctor, is he?",
                    "ua": "He isn't a doctor, is he?"
                },
                {
                    "en": "They aren't British, are they?",
                    "ua": "They are not British, are they?"
                }
            ]
        },
        {
            "label": "Past Simple — WAS/WERE",
            "color": "purple",
            "description": "In the past tense we use was/were:",
            "examples": [
                {
                    "en": "It was great, wasn't it?",
                    "ua": "It was great, true?"
                },
                {
                    "en": "They were late, weren't they?",
                    "ua": "They were late, right?"
                },
                {
                    "en": "She wasn't there, was she?",
                    "ua": "She wasn't there, right?"
                }
            ],
            "note": "📌 Rule: positive + negative / negative + positive"
        }
    ]
}

{
    "title": "3. Question Tags with DO/DOES/DID",
    "sections": [
        {
            "label": "Present Simple",
            "color": "blue",
            "description": "In Present Simple we use <strong>do/does</strong> in the tag:",
            "examples": [
                {
                    "en": "You like coffee, don't you?",
                    "ua": "You like coffee, right?"
                },
                {
                    "en": "She works here, doesn't she?",
                    "ua": "She works here, right?"
                },
                {
                    "en": "They live in London, don't they?",
                    "ua": "They live in London, don't they?"
                },
                {
                    "en": "He knows the answer, doesn't he?",
                    "ua": "Він знає відповідь, так?"
                }
            ]
        },
        {
            "label": "Негативні речення",
            "color": "amber",
            "description": "З негативними реченнями tag позитивний:",
            "examples": [
                {
                    "en": "You don't like coffee, do you?",
                    "ua": "Тобі не подобається кава, так?"
                },
                {
                    "en": "She doesn't work here, does she?",
                    "ua": "She doesn't work here, right?"
                },
                {
                    "en": "They don't live in London, do they?",
                    "ua": "They don't live in London, right?"
                }
            ]
        },
        {
            "label": "Past Simple",
            "color": "rose",
            "description": "In Past Simple we use <strong>did</strong>:",
            "examples": [
                {
                    "en": "You saw the movie, didn't you?",
                    "ua": "You saw the movie, right?"
                },
                {
                    "en": "She called you, didn't she?",
                    "ua": "She called you, didn't she?"
                },
                {
                    "en": "They didn't come, did they? yes?",
                    "ua": "Вони не прийшли, так?"
                }
            ],
            "note": "📌 Tag always uses the auxiliary verb do/does/did"
        }
    ]
}

{
    "title": "4. Question Tags with modal verbs",
    "sections": [
        {
            "label": "CAN / COULD / WILL / WOULD",
            "color": "emerald",
            "description": "With modal verbs, we repeat the modal in the tag:",
            "examples": [
                {
                    "en": "You can swim, can't you?",
                    "ua": "You can swim, yes?"
                },
                {
                    "en": "She will come, won't she?",
                    "ua": "She will come, won't she?"
                },
                {
                    "en": "They could help, couldn't they?",
                    "ua": "They could help, right?"
                },
                {
                    "en": "He would like it, wouldn't he?",
                    "ua": " yes?"
                }
            ]
        },
        {
            "label": "SHOULD / MUST / MAY",
            "color": "sky",
            "description": "Other modal verbs work the same way:",
            "examples": [
                {
                    "en": "We should go, shouldn't we?",
                    "ua": "We should go, yes?"
                },
                {
                    "en": "You must be tired, mustn't you?",
                    "ua": "You must be tired, right?"
                },
                {
                    "en": "She might come, mightn't she?",
                    "ua": "She might come, mightn't she?"
                }
            ]
        },
        {
            "label": "Negative forms",
            "color": "purple",
            "description": "With negative modal forms:",
            "examples": [
                {
                    "en": "You can't swim, can you?",
                    "ua": "You can't swim, right?"
                },
                {
                    "en": "She won't come, will she?",
                    "ua": "She won't come, will she?"
                },
                {
                    "en": "They shouldn't worry, should they? yes?",
                    "ua": "Їм не варто хвилюватися, так?"
                }
            ],
            "note": "📌 The modal verb from the sentence is repeated in tag"
        }
    ]
}

{
    "title": "5. Question Tags with HAVE/HAS",
    "sections": [
        {
            "label": "Present Perfect",
            "color": "amber",
            "description": "In the Present Perfect we also use have/has:",
            "examples": [
                {
                    "en": "You have seen the movie, haven't you? she?",
                    "ua": "Ти бачив цей фільм, так?"
                },
                {
                    "en": "She has finished, hasn't she?",
                    "ua": "She has finished, right?"
                },
                {
                    "en": "They haven't arrived, have they?",
                    "ua": "They haven't arrived, have they?"
                }
            ]
        },
        {
            "label": "HAVE GOT",
            "color": "blue",
            "description": "With <strong>have got</strong> (mother) we use have/has in tag:",
            "examples": [
                {
                    "en": "You have got a car, haven't you?",
                    "ua": "You have got a car, haven't you?"
                },
                {
                    "en": "She has got a dog, hasn't she?",
                    "ua": "She has got a dog, right?"
                },
                {
                    "en": "They haven't got time, have they?",
                    "ua": "They don't have time, do they?"
                }
            ]
        },
        {
            "label": "American version",
            "color": "rose",
            "description": "In American English, do is often used with <strong>have</strong> (have):",
            "examples": [
                {
                    "en": "You have a car, don't you?",
                    "ua": "You have a car, don't you? yes?"
                },
                {
                    "en": "She has a dog, doesn't she?",
                    "ua": "She has a dog, right?"
                }
            ],
            "note": "📌 British variant: have got + haven't/hasn't, American: have + don't/doesn't"
        }
    ]
}

{
    "title": "6. Question Tags with other tenses",
    "sections": [
        {
            "label": "Present Continuous",
            "color": "emerald",
            "description": "In Present Continuous we use am/is/are:",
            "examples": [
                {
                    "en": "You are working now, aren't you?",
                    "ua": "You are working now, yes?"
                },
                {
                    "en": "She is coming, isn't she?",
                    "ua": "She is leaving, right?"
                },
                {
                    "en": "They aren't playing, are they?",
                    "ua": "They are not playing, right?"
                }
            ]
        },
        {
            "label": "Past Continuous",
            "color": "sky",
            "description": "In the Past Continuous we use was/were:",
            "examples": [
                {
                    "en": "You were sleeping, weren't you?",
                    "ua": "You were sleeping, right?"
                },
                {
                    "en": "She was studying, wasn't she?",
                    "ua": "She was studying, right?"
                },
                {
                    "en": "They weren't watching TV, were they?",
                    "ua": " yes?"
                }
            ]
        },
        {
            "label": "Future Simple",
            "color": "purple",
            "description": "In Future Simple with <strong>will</strong>:",
            "examples": [
                {
                    "en": "You will help me, won't you?",
                    "ua": "You will help me, yes?"
                },
                {
                    "en": "She will come tomorrow, won't you she?",
                    "ua": "She will come tomorrow, right?"
                },
                {
                    "en": "They won't be late, will they?",
                    "ua": "They won't be late, will they?"
                }
            ],
            "note": "📌 Tag uses an auxiliary verb from the sentence"
        }
    ]
}

{
    "title": "7. Special cases and exceptions",
    "sections": [
        {
            "label": "I AM → AREN'T I?",
            "color": "rose",
            "description": "With <strong>I am</strong> tag always <strong>aren't I?</strong> (not amn't I):",
            "examples": [
                {
                    "en": "I am right, aren't I?",
                    "ua": "I am right, yes?"
                },
                {
                    "en": "I am late, aren't I?",
                    "ua": "I am late, aren't I?"
                },
                {
                    "en": "I am invited, aren't I?",
                    "ua": "Мене запросили, так?"
                }
            ]
        },
        {
            "label": "Imperatives (наказовий спосіб)",
            "color": "amber",
            "description": "З наказовим способом використовуємо <strong>will you?</strong>:",
            "examples": [
                {
                    "en": "Close the door, will you?",
                    "ua": "Close the door, will you?"
                },
                {
                    "en": "Help me, will you?",
                    "ua": "Help me, will you?"
                },
                {
                    "en": "Don't be late, will you?[[[CODX_9]]]Don't be late, will you?",
                    "ua": "Не спізнюйся, добре?"
                }
            ]
        },
        {
            "label": "LET'S → SHALL WE?",
            "color": "blue",
            "description": "With <strong>Let's</strong> always <strong>shall we?</strong>:",
            "examples": [
                {
                    "en": "Let's go to the cinema, shall we?",
                    "ua": "Let's have a break, shall we?"
                },
                {
                    "en": "Let's have a break, shall we?",
                    "ua": "Let's take a break, okay?"
                }
            ]
        },
        {
            "label": "THIS/THAT → IT",
            "color": "emerald",
            "description": "In the tag instead of this/that we use <strong>it</strong>:",
            "examples": [
                {
                    "en": "This is your book, isn't it?",
                    "ua": " yes?"
                },
                {
                    "en": "That was interesting, wasn't it?",
                    "ua": "It was interesting, right?"
                }
            ],
            "note": "📌 Special rules for I am, imperatives, let's, this/that"
        }
    ]
}

{
    "title": "8. Intonation and use",
    "sections": [
        {
            "label": "Falling intonation ↘",
            "color": "emerald",
            "description": "<strong>Falling intonation</strong> — when we are sure and want confirmation:",
            "examples": [
                {
                    "en": "It's a nice day, isn't it? ↘",
                    "ua": "Nice day, isn't it? (sure)"
                },
                {
                    "en": "You like coffee, don't you? ↘",
                    "ua": "You like coffee, right? (we know the answer)"
                }
            ]
        },
        {
            "label": "Rising intonation ↗",
            "color": "sky",
            "description": "<strong>Rising intonation</strong> - when we are not sure and really ask:",
            "examples": [
                {
                    "en": "You live in London, don't you? ↗",
                    "ua": "You live in London, right? (not sure)"
                },
                {
                    "en": "She is coming, isn't she? ↗",
                    "ua": "She's leaving, isn't she? (really asking)"
                }
            ]
        },
        {
            "label": "Usage",
            "color": "purple",
            "description": "Question tags are used for:",
            "examples": [
                {
                    "en": "Confirming information",
                    "ua": "Confirming information"
                },
                {
                    "en": "Starting a conversation",
                    "ua": "Being polite"
                },
                {
                    "en": "Being polite",
                    "ua": "Politeness"
                },
                {
                    "en": "Showing interest",
                    "ua": "Expression of interest"
                }
            ],
            "note": "📌 Intonation is important: ↘ confirmation, ↗ real question"
        }
    ]
}

{
    "title": "9. Quick Table Question Tags",
    "intro": "Basic rules for forming question tags:",
    "rows": [
        {
            "en": "TO BE (am/is/are/was/were)",
            "ua": "Verb to be",
            "note": "She is happy, isn't she? / She isn't happy, is she?"
        },
        {
            "en": "DO/DOES/DID",
            "ua": "Simple times",
            "note": "You like it, don't you? / You don't like it, do you?"
        },
        {
            "en": "MODALS (can/will/should...)",
            "ua": "Modal verbs",
            "note": "She can swim, can't she? / She can't swim, can she?"
        },
        {
            "en": "HAVE/HAS (got/Perfect)",
            "ua": "Have got and Perfect",
            "note": "You have seen it, haven't you?"
        },
        {
            "en": "Special: I AM",
            "ua": "Exception from I am",
            "note": "I am right, aren't I? (NOT: amn't I)"
        },
        {
            "en": "Imperatives",
            "ua": "Imperative",
            "note": "Close the door, will you?"
        }
    ],
    "warning": "📌 Basic rule: <strong>positive + negative / negative + positive</strong>"
}

{
    "title": "10. Typical errors",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "The same form in the sentence and the tag.",
            "wrong": "❌ She is happy, is she?",
            "right": "​​​​ <span class="font-mono">She is happy, isn't she?</span>[[[CODX_6]]]Error 2. 3. subject in tag."
        },
        {
            "label": "Помилка 2",
            "color": "amber",
            "title": "Неправильний tag з I am (amn't I — не існує, am I not — формальне).",
            "wrong": "❌ I am right, amn't I?",
            "right": "✅ <span class="font-mono">I am right, aren't I?</span>"
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Використання do/does замість модального у tag.",
            "wrong": "❌ She can swim, doesn't she?",
            "right": "✅ <span class="font-mono">She can swim, can't she?</span>"
        },
        {
            "label": "Помилка 4",
            "color": "purple",
            "title": "Повторення повного підмета у tag.",
            "wrong": "❌ John is happy, isn't John?",
            "right": " ✅ <span class="font-mono">John is happy, isn't he?</span>"
        }
    ]
}

{
    "title": "12. Practice",
    "select_title": "Exercise 1. Choose the correct tag",
    "select_intro": "Choose the correct question tag for each sentence.",
    "selects": [
        {
            "label": "She is happy, _____? (isn't she / doesn't she / haven't she)",
            "prompt": "Which tag is correct?"
        },
        {
            "label": "You like coffee, _____? (don't you / aren't you / isn't it)",
            "prompt": "Which tag is correct?"
        },
        {
            "label": "They can swim, _____? (can they / can't they / don't they)",
            "prompt": "Which tag is correct?"
        },
        {
            "label": "I am right, _____? (am I not / aren't I / isn't I)",
            "prompt": "Which tag is correct?"
        }
    ],
    "options": [
        "First option",
        "Second option",
        "Third option"
    ],
    "input_title": "Exercise 2. Add question tag",
    "input_intro": "Add the correct one question tag to the sentence.",
    "inputs": [
        {
            "before": "She is tired, ",
            "after": "?"
        },
        {
            "before": "You don't like tea, ",
            "after": "?"
        },
        {
            "before": "He can drive, ",
            "after": "?"
        },
        {
            "before": "They won't be late. she?",
            "after": "?"
        }
    ],
    "rephrase_title": "Вправа 3. Виправ помилки",
    "rephrase_intro": "Знайди і виправ помилку у question tag.",
    "rephrase": [
        {
            "example_label": "Приклад:",
            "example_original": "She is happy, is she?",
            "example_target": "She is happy, isn't she?"
        },
        {
            "original": "1. You like coffee, aren't you?",
            "placeholder": "Fix the error"
        },
        {
            "original": "2. She can swim, doesn't she?",
            "placeholder": "Fix the error"
        },
        {
            "original": "3. Am I not? to the subject",
            "placeholder": "Виправ помилку"
        }
    ]
}

{
    "title": "Інші теми з розділу Види питальних речень",
    "items": [
        {
            "label": "Yes/No Questions — Загальні питання",
            "current": false
        },
        {
            "label": "Wh-Questions — Спеціальні питання",
            "current": false
        },
        {
            "label": "Alternative Questions — Альтернативні питання",
            "current": false
        },
        {
            "label": "Subject Questions — Питання до підмета",
            "current": false
        },
        {
            "label": "Question Tags — Sectional questions (current)",
            "current": true
        }
    ]
}
